// Lifetime sales per customer, independent of the view's dimensions
{ FIXED [Customer ID] : SUM([Sales]) }

// Overall average order value across the whole table
{ FIXED : SUM([Sales]) / COUNTD([Order ID]) }

// Lifetime value per customer, independent of the view's other fields
Customer LTV = { FIXED [Customer ID] : SUM([Sales]) }

// Each customer's first order date (cohort analysis)
First Purchase = { FIXED [Customer ID] : MIN([Order Date]) }

// State total that ignores the sheet's other dimensions
Sales per State = { FIXED [State] : SUM([Sales]) }

// Each customer's lifetime sales, independent of the view
Customer LTV = {FIXED [Customer ID] : SUM([Sales])}

// Flag high-value customers
High Value = IF [Customer LTV] > 100000 THEN "High Value" ELSE "Regular" END

// This view's sales as a share of the customer's lifetime spend
Share of LTV = SUM([Sales]) / MIN([Customer LTV])
